chapters.teach:
```c
int compte_pairs(int t[], int n) {
    int c = 0;
    for (int i = 0; i < n; i++) { if (t[i] % 2 == 0) c++; }
    return c;
}
```

chapters.starterCode:
#include <stdio.h>
// définis compte_pairs ici
int main(void) {
    int t[4] = {1, 2, 3, 4};
    // printf compte_pairs(t, 4)
    return 0;
}

chapters.correction:
#include <stdio.h>
int compte_pairs(int t[], int n) {
    int c = 0;
    for (int i = 0; i < n; i++) { if (t[i] % 2 == 0) c++; }
    return c;
}
int main(void) {
    int t[4] = {1, 2, 3, 4};
    printf("%d\n", compte_pairs(t, 4));
    return 0;
}

