chapters.teach:
```c
int moyenne(int t[], int n) {
    int s = 0;
    for (int i = 0; i < n; i++) { s += t[i]; }
    return s / n;
}
```

chapters.starterCode:
#include <stdio.h>
// définis moyenne ici
int main(void) {
    int t[3] = {12, 18, 12};
    // printf moyenne(t, 3)
    return 0;
}

chapters.correction:
#include <stdio.h>
int moyenne(int t[], int n) {
    int s = 0;
    for (int i = 0; i < n; i++) { s += t[i]; }
    return s / n;
}
int main(void) {
    int t[3] = {12, 18, 12};
    printf("%d\n", moyenne(t, 3));
    return 0;
}
